import React, { useState, useMemo } from "react";
import { useFeatures } from "./hooks/useFeature";
import FeatureCard from "./components/FeatureCard";
import FeatureModal from "./components/FeatureModal";
import FilterBar from "./components/FilterBar";
import StatsBar from "./components/StatsBar";
import EmptyState from "./components/EmptyState";
import { STATUSES } from "./utils/costants";

export default function App() {
	const { features, addFeature, updateFeature, deleteFeature, updateStatus } = useFeatures();
	const [filter, setFilter] = useState("All");
	const [modal, setModal] = useState(null); // null | "add" | feature-object
	const [isAdminMode, setIsAdminMode] = useState(false); // Toggle for admin functionality

	const filtered = useMemo(() => {
		if (filter === "All") return features;
		return features.filter((f) => f.status === filter);
	}, [features, filter]);

	const counts = useMemo(() => {
		const c = {};
		STATUSES.forEach((s) => { c[s] = features.filter((f) => f.status === s).length; });
		return c;
	}, [features]);

	async function handleAddFeature(newData) {
		try {
			const formData = new FormData();
			formData.append("title", newData.title);
			formData.append("description", newData.description);
			formData.append("priority", newData.priority);
			formData.append("status", newData.status);
			if (newData.image instanceof File) {
				formData.append("image", newData.image);
			}
			await addFeature(formData);
		} catch (err) {
			console.error("Error adding feature:", err);
		}
	}

	async function handleEditFeature(updatedData) {
		try {
			const formData = new FormData();
			formData.append("title", updatedData.title);
			formData.append("description", updatedData.description);
			formData.append("priority", updatedData.priority);
			formData.append("status", updatedData.status);
			if (updatedData.image instanceof File) {
				formData.append("image", updatedData.image);
			}
			await updateFeature(updatedData.id, formData);
		} catch (err) {
			console.error("Error updating feature:", err);
		}
	}

	async function handleDeleteFeature(id) {
		if (!window.confirm("Are you sure you want to delete this feature?")) return;
		try {
			await deleteFeature(id);
		} catch (err) {
			console.error("Error deleting feature:", err);
		}
	}

	async function handleStatusChange(id, newStatus) {
		try {
			await updateStatus(id, newStatus);
		} catch (err) {
			console.error("Error updating status:", err);
		}
	}

	return (
		<div className="app app-layout">
			<aside className="sidebar-nav">
				<div className="sidebar-title">Feature Tracker</div>
				<FilterBar active={filter} onChange={setFilter} counts={counts} />
				<button className="btn btn-ghost sidebar-history" onClick={() => { window.history.pushState({}, '', '/history'); window.setAppRoute && window.setAppRoute('history'); }}>View All History</button>
			</aside>
			<main className="main-content">
				{/* ── Header ── */}
				<header className="app-header">
					<div className="header-left">
						<h1 className="app-title">Feature Tracker</h1>
						<p className="app-subtitle">Manage and track feature requests</p>
					</div>
					<button
						className="btn btn-primary"
						onClick={() => setModal("add")}
						style={{ display: "flex", alignItems: "center", gap: "8px" }}
					>
						+ Add Feature
					</button>
				</header>

				{/* ── Stats ── */}
				<StatsBar features={features} />

				{/* ── Cards ── */}
				{filtered.length === 0 ? (
					<EmptyState filter={filter} />
				) : (
					<div className="cards-grid">
						{filtered.map((f) => (
							<FeatureCard
								key={f.id}
								feature={f}
								onEdit={() => setModal(f)}
								onDelete={() => handleDeleteFeature(f.id)}
								onStatusChange={(newStatus) => handleStatusChange(f.id, newStatus)}
							/>
						))}
					</div>
				)}

				{/* ── Modal for Add/Edit ── */}
				{modal && modal !== "add" && (
					<FeatureModal
						feature={modal}
						onSave={handleEditFeature}
						onClose={() => setModal(null)}
					/>
				)}

				{/* ── Modal for Add ── */}
				{modal === "add" && (
					<FeatureModal
						feature={null}
						onSave={handleAddFeature}
						onClose={() => setModal(null)}
					/>
				)}
			</main>
		</div>
	);
}
